using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// --- 1. GetTypeInfo<T>(): strongly-typed metadata retrieval ---
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

JsonTypeInfo<WeatherForecast> typeInfo = options.GetTypeInfo<WeatherForecast>();
Console.WriteLine($"GetTypeInfo<WeatherForecast>() → Type = {typeInfo.Type.Name}");

string json = JsonSerializer.Serialize(
    new WeatherForecast("Seattle", 62),
    typeInfo);
Console.WriteLine($"Serialized: {json}");

// --- 2. TryGetTypeInfo<T>(): check-without-throwing ---

// 2a. Type that IS resolvable (default reflection resolver handles it)
if (options.TryGetTypeInfo<WeatherForecast>(out var resolved))
    Console.WriteLine($"\nTryGetTypeInfo<WeatherForecast>() → found ({resolved!.Type.Name})");
else
    Console.WriteLine("\nTryGetTypeInfo<WeatherForecast>() → not found");

// 2b. Type that is NOT resolvable (empty resolver knows nothing)
var restricted = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver
    {
        Modifiers =
        {
            // Reject every type by clearing its properties
            ti => { if (ti.Type == typeof(UnknownThing)) throw new NotSupportedException(); }
        }
    }
};
// Use a resolver chain that has no knowledge of UnknownThing
var empty = new JsonSerializerOptions { TypeInfoResolver = JsonTypeInfoResolver.Combine() };

if (empty.TryGetTypeInfo<UnknownThing>(out var notResolved))
    Console.WriteLine($"TryGetTypeInfo<UnknownThing>() → found");
else
    Console.WriteLine($"TryGetTypeInfo<UnknownThing>() → not found (no exception thrown!)");

// --- types ---
public record WeatherForecast(string City, int TempF);
public record UnknownThing(string Data);

